starter_code:
.container {
  display: flex;
  gap: 16px;
  padding: 16px;
}

.column {
  flex: 1;
  padding: 20px;
  background: #f0f0f0;
  border-radius: 8px;
  text-align: center;
}

demo.code:
.flex-demo {
  display: flex;
  gap: 12px;
  padding: 16px;
}

.flex-demo > div {
  flex: 1;
  padding: 24px;
  background: linear-gradient(135deg, #667eea, #764ba2);
  color: white;
  border-radius: 12px;
  text-align: center;
  font-weight: bold;
}
